 1→import { Sandbox } from "e2b";
 2→import { env } from "@/env/server";
 3→import { sandboxRepo } from "@/server/db/repos/sandbox.repo";
 4→
 5→export const E2B_TEMPLATE_NAME = "runagents-dev-20260227";
 6→export const E2B_TIMEOUT_MS = 120_000;
 7→
 8→export function getE2BApiKey(): string {
 9→  if (!env.E2B_API_KEY) throw new Error("E2B_API_KEY is not configured");
10→  return env.E2B_API_KEY;
11→}
12→
13→/** Single-quote shell escape for safe CLI argument passing */
14→export function esc(v: string): string {
15→  return `'${v.replace(/'/g, "'\\''")}'`;
16→}
17→
18→export async function connectSandbox(e2bSandboxId: string): Promise<Sandbox> {
19→  return Sandbox.connect(e2bSandboxId, {
20→    apiKey: getE2BApiKey(),
21→    timeoutMs: E2B_TIMEOUT_MS,
22→  });
23→}
24→
25→export async function runOrThrow(
26→  sandbox: Sandbox,
27→  cmd: string,
28→  label: string,
29→  logCmd?: string,
30→) {
31→  console.log(`[e2b] ${label} cmd:`, logCmd ?? cmd);
32→  try {
33→    const result = await sandbox.commands.run(cmd);
34→    const stdout = result.stdout ?? "";
35→    const stderr = result.stderr ?? "";
36→    if (result.exitCode !== 0) {
37→      const errMsg = [
38→        `[e2b] ${label} FAILED (exit ${result.exitCode})`,
39→        stdout && `stdout: ${stdout}`,
40→        stderr && `stderr: ${stderr}`,
41→      ]
42→        .filter(Boolean)
43→        .join("\n");
44→      console.error(errMsg);
45→      throw new Error(
46→        stderr.trim() ||
47→          stdout.trim() ||
48→          `${label} failed (exit ${result.exitCode})`,
49→      );
50→    }
51→    console.log(`[e2b] ${label} OK`);
52→    return result;
53→  } catch (err: unknown) {
54→    // E2B SDK throws CommandExitError with a `result` property on non-zero exit
55→    const cmdErr = err as {
56→      result?: { stdout?: string; stderr?: string; exitCode?: number };
57→      message?: string;
58→    };
59→    if (cmdErr.result) {
60→      const stdout = cmdErr.result.stdout ?? "";
61→      const stderr = cmdErr.result.stderr ?? "";
62→      const exitCode = cmdErr.result.exitCode ?? 1;
63→      const errMsg = [
64→        `[e2b] ${label} FAILED (exit ${exitCode})`,
65→        stdout && `stdout: ${stdout}`,
66→        stderr && `stderr: ${stderr}`,
67→      ]
68→        .filter(Boolean)
69→        .join("\n");
70→      console.error(errMsg);
71→      throw new Error(
72→        stderr.trim() || stdout.trim() || `${label} failed (exit ${exitCode})`,
73→      );
74→    }
75→    // Not a CommandExitError — log and rethrow
76→    console.error(`[e2b] ${label} exception:`, cmdErr.message ?? err);
77→    throw err;
78→  }
79→}
