 17→export function useDeleteSandbox() {
 18→  const queryClient = useQueryClient();
 19→  const router = useRouter();
 20→  const { data: activeOrg } = authClient.useActiveOrganization();
 21→  const orgId = activeOrg?.id;
 22→
 23→  return useMutation({
 24→    mutationFn: async (input: { sandboxId: string }) => {
 25→      const result = await deleteSandbox(input);
 26→      if (result && typeof result === "object" && "error" in result) {
 27→        throw Object.assign(new Error(String(result.error)), { code: result.error });
 28→      }
 29→      return result;
 30→    },
 31→    onSuccess: () => {
 32→      if (orgId) {
 33→        queryClient.invalidateQueries({ queryKey: sandboxKeys.all(orgId) });
 34→      }
 35→      router.push("/dashboard");
 36→    },
 37→  });
 38→}
 39→
 40→export function useSandboxRuntime(sandboxId: string) {
 41→  return useQuery({
 42→    queryKey: sandboxKeys.runtime(sandboxId),
 43→    queryFn: async () => {
 44→      const result = await getSandboxRuntimeStatus({ sandboxId });
 45→      if (result && typeof result === "object" && "error" in result) {
 46→        throw Object.assign(new Error(String(result.error)), { code: result.error });
 47→      }
 48→      return result;
 49→    },
 50→    enabled: !!sandboxId,
 51→    retry: false,
 52→    staleTime: 120_000,
 53→    refetchInterval: 120_000,
 54→    refetchOnWindowFocus: false,
 55→  });
 56→}
 57→
 58→export function useWakeSandbox() {
 59→  const queryClient = useQueryClient();
 60→  const { data: activeOrg } = authClient.useActiveOrganization();
 61→  const orgId = activeOrg?.id;
 62→
 63→  return useMutation({
 64→    mutationFn: async (input: { sandboxId: string }) => {
 65→      const result = await wakeSandbox(input);
 66→      if (result && typeof result === "object" && "error" in result) {
 67→        throw Object.assign(new Error(String(result.error)), { code: result.error });
 68→      }
 69→      return result;
 70→    },
 71→    onSuccess: (_result, variables) => {
 72→      queryClient.invalidateQueries({
 73→        queryKey: sandboxKeys.runtime(variables.sandboxId),
 74→      });
 75→      if (orgId) {
 76→        queryClient.invalidateQueries({ queryKey: sandboxKeys.all(orgId) });
 77→      }
 78→    },
 79→  });
 80→}
