 89→        throw Object.assign(new Error(String(result.error)), { code: result.error });
 90→      }
 91→      return result;
 92→    },
 93→    onSuccess: (_result, variables) => {
 94→      queryClient.invalidateQueries({
 95→        queryKey: sandboxKeys.runtime(variables.sandboxId),
 96→      });
 97→    },
 98→  });
 99→}
