 18→
 19→interface CreateSnapshotDialogProps {
 20→  sandboxId: string;
 21→  open: boolean;
 22→  onOpenChange: (open: boolean) => void;
 23→  onSubscriptionRequired?: () => void;
 24→}
 25→
 26→export function CreateSnapshotDialog({
 27→  sandboxId,
 28→  open,
 29→  onOpenChange,
 30→  onSubscriptionRequired,
 31→}: CreateSnapshotDialogProps) {
 32→  const [name, setName] = useState("");
 33→  const { mutate: createSnapshot, isPending } = useCreateSnapshot();
 34→
 35→  function handleOpenChange(next: boolean) {
 36→    if (isPending) return;
 37→    if (!next) setName("");
 38→    onOpenChange(next);
 39→  }
 40→
 41→  function handleSubmit(e: React.FormEvent) {
 42→    e.preventDefault();
 43→    if (!name.trim()) return;
 44→
 45→    createSnapshot(
 46→      { sandboxId, name: name.trim() },
 47→      {
 48→        onSuccess: () => {
 49→          handleOpenChange(false);
 50→          toast.success("Snapshot created");
 51→        },
 52→        onError: (err) => {
 53→          if ((err as { code?: string }).code === "SUBSCRIPTION_REQUIRED") {
 54→            handleOpenChange(false);
 55→            onSubscriptionRequired?.();
 56→            return;
 57→          }
 58→          toast.error(err.message ?? "Failed to create snapshot");
 59→        },
 60→      },
 61→    );
 62→  }
 63→
 64→  return (
 65→    <Dialog open={open} onOpenChange={handleOpenChange}>
 66→      <DialogContent className="sm:max-w-sm" preventClose={isPending}>
 67→        <DialogHeader>
 68→          <div className="flex items-center gap-2">
 69→            <div className="flex size-8 items-center justify-center rounded-md bg-primary/10 text-primary">
 70→              <Camera className="size-4" />
 71→            </div>
 72→            <DialogTitle>New Snapshot</DialogTitle>
 73→          </div>
 74→          <DialogDescription>
 75→            Save the current state of your sandbox environment.
 76→          </DialogDescription>
 77→        </DialogHeader>
 78→
 79→        <form onSubmit={handleSubmit} className="space-y-4">
 80→          <div className="space-y-2">
 81→            <Label htmlFor="snapshot-name">Snapshot Name</Label>
 82→            <Input
 83→              id="snapshot-name"
 84→              placeholder="before-update-v2"
 85→              value={name}
 86→              onChange={(e) => setName(e.target.value)}
 87→              disabled={isPending}
 88→              autoComplete="off"
 89→              autoFocus
 90→            />
 91→          </div>
 92→
 93→          <DialogFooter>
 94→            <Button
 95→              type="button"
 96→              variant="outline"
 97→              onClick={() => handleOpenChange(false)}
 98→              disabled={isPending}
 99→            >
100→              Cancel
101→            </Button>
102→            <Button type="submit" disabled={!name.trim() || isPending}>
103→              {isPending ? (
104→                <>
105→                  <Loader2 className="mr-2 size-4 animate-spin" />
106→                  Saving…
107→                </>
108→              ) : (
109→                "Save Snapshot"
110→              )}
111→            </Button>
112→          </DialogFooter>
113→        </form>
114→      </DialogContent>
115→    </Dialog>
116→  );
117→}
